1	const PROCESSING_FEE = 5;
2	const BLOCK_PRICE = 60;
3	
4	const BASE_PREMIUM_BY_ITEM_TYPE: Record<string, number> = {
5	  sword: 100,
6	  amulet: 60,
7	  staff: 80,
8	  potion: 40,
9	  rune: 25,
10	  moonstone: 25,
11	};
12	
13	type Item = { type: string };
14	type Step = { items: Item[] };
15	type Scenario = { steps: Step[] };
16	
17	const basePremiumFor = (item: Item): number =>
18	  BASE_PREMIUM_BY_ITEM_TYPE[item.type] ?? 0;
19	
20	const isBlockOfThreeRunes = (items: Item[]): boolean =>
21	  items.length === 3 && items.every((item) => item.type === "rune");
22	
23	const sumBasePremiums = (items: Item[]): number => {
24	  if (isBlockOfThreeRunes(items)) return BLOCK_PRICE;
25	  return items.reduce((sum, item) => sum + basePremiumFor(item), 0);
26	};
27	
28	const quotePremiumFor = (step: Step): number =>
29	  sumBasePremiums(step.items) + PROCESSING_FEE;
30	
31	export const processScenario = (input: unknown): unknown => {
32	  const { steps } = input as Scenario;
33	  return { results: steps.map((step) => ({ premium: quotePremiumFor(step) })) };
34	};
